import{_ as n,C as o,o as s,c as l,E as i,w as r,a,a0 as d}from"./chunks/framework.CkNTPv-z.js";const b=JSON.parse('{"title":"Moving to Switzerland","description":"Immigration pathways and relocation guide for Switzerland","frontmatter":{"layout":"doc","title":"Moving to Switzerland","description":"Immigration pathways and relocation guide for Switzerland"},"headers":[],"relativePath":"europe/switzerland/moving-there.md","filePath":"europe/switzerland/moving-there.md","lastUpdated":null}'),h={name:"europe/switzerland/moving-there.md"};function c(m,t,g,u,p,f){const e=o("Badge");return s(),l("div",null,[i(e,{variant:"green"},{default:r(()=>[...t[0]||(t[0]=[a("EU/EFTA Free Movement",-1)])]),_:1}),i(e,{variant:"yellow"},{default:r(()=>[...t[1]||(t[1]=[a("Non-EU Quota System",-1)])]),_:1}),t[2]||(t[2]=d('<h1 id="moving-to-switzerland" tabindex="-1">Moving to Switzerland <a class="header-anchor" href="#moving-to-switzerland" aria-label="Permalink to &quot;Moving to Switzerland&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><h3 id="eu-efta-citizens" tabindex="-1">EU/EFTA Citizens <a class="header-anchor" href="#eu-efta-citizens" aria-label="Permalink to &quot;EU/EFTA Citizens&quot;">​</a></h3><p>Switzerland has <strong>free movement agreements</strong> with the EU and EFTA:</p><ul><li><strong>Up to 3 months</strong>: No registration required</li><li><strong>Over 3 months</strong>: Must register with the cantonal migration office for a <strong>B permit</strong> (residence permit)</li><li><strong>Requirements</strong>: Valid passport, proof of employment, sufficient funds, or study enrollment</li><li><strong>Right to work</strong>: Automatic, no additional work permit needed</li><li><strong>After 5 years</strong>: Eligible for <strong>C permit</strong> (permanent residence)</li><li><strong>After 10 years</strong>: Eligible for Swiss citizenship</li></ul><h3 id="non-eu-efta-citizens" tabindex="-1">Non-EU/EFTA Citizens <a class="header-anchor" href="#non-eu-efta-citizens" aria-label="Permalink to &quot;Non-EU/EFTA Citizens&quot;">​</a></h3><p>Switzerland operates a <strong>strict quota system</strong> for non-EU/EFTA nationals:</p><table tabindex="0"><thead><tr><th>Permit Type</th><th>Description</th><th>Requirements</th><th>Duration</th></tr></thead><tbody><tr><td>L Permit</td><td>Short-term work</td><td>Job offer, limited to 12 months</td><td>Up to 12 months</td></tr><tr><td>B Permit</td><td>Residence (work)</td><td>Job offer, priority given to EU/EFTA nationals</td><td>1 year, renewable</td></tr><tr><td>B Permit (family)</td><td>Family reunification</td><td>Relationship to Swiss/EU resident</td><td>1 year, renewable</td></tr><tr><td>Student Visa</td><td>Full-time study</td><td>University acceptance, funds proof (21,000+ CHF/year)</td><td>Duration of studies</td></tr><tr><td>Retirement Visa</td><td>Retirees</td><td>Sufficient funds (no work allowed)</td><td>1 year, renewable</td></tr></tbody></table><p><strong>Key restrictions for non-EU:</strong></p><ul><li>Annual quotas limit the number of B and L permits for non-EU nationals</li><li>Employer must prove no suitable Swiss/EU candidate exists</li><li>Work permits tied to specific employer</li><li>Highly skilled professionals (managers, specialists, researchers) prioritized</li><li>Switching jobs requires new permit approval</li></ul><h3 id="uk-citizens-post-brexit" tabindex="-1">UK Citizens (Post-Brexit) <a class="header-anchor" href="#uk-citizens-post-brexit" aria-label="Permalink to &quot;UK Citizens (Post-Brexit)&quot;">​</a></h3><ul><li>UK-Switzerland <strong>Migration and Mobility Agreement</strong> (limited)</li><li>UK citizens can enter visa-free for 90 days</li><li>For longer stays: Apply through the cantonal migration office</li><li>Work, study, and family reunification paths available</li><li>UK citizens do not have free movement rights</li></ul><h2 id="digital-nomad-remote-work" tabindex="-1">Digital Nomad / Remote Work <a class="header-anchor" href="#digital-nomad-remote-work" aria-label="Permalink to &quot;Digital Nomad / Remote Work&quot;">​</a></h2><p>Switzerland does <strong>not</strong> have a specific digital nomad visa. Options for remote workers:</p><ul><li><strong>B Permit with remote employment</strong>: Possible if the employer has a Swiss presence or through a Swiss payroll company</li><li><strong>L Permit</strong>: Short-term options limited</li><li>Some cantons are more flexible than others</li><li>B permit requires a residence in Switzerland</li><li><strong>Border crossing</strong>: Remote workers from neighbouring countries can live in nearby EU countries and commute</li></ul><h2 id="moving-checklist" tabindex="-1">Moving Checklist <a class="header-anchor" href="#moving-checklist" aria-label="Permalink to &quot;Moving Checklist&quot;">​</a></h2><h3 id="before-moving" tabindex="-1">Before Moving <a class="header-anchor" href="#before-moving" aria-label="Permalink to &quot;Before Moving&quot;">​</a></h3><ul><li>[ ] <strong>Passport</strong>: Valid for at least 6 months</li><li>[ ] <strong>Visa/Residence</strong>: Check requirements based on nationality</li><li>[ ] <strong>Health Insurance</strong>: Mandatory within 3 months of arrival (compare on comparis.ch)</li><li>[ ] <strong>HRT</strong>: Get 3-6 month supply and doctor&#39;s letter (English, German, or French)</li><li>[ ] <strong>Medical Records</strong>: Translated into German or French</li><li>[ ] <strong>Banking</strong>: International banking options</li><li>[ ] <strong>Housing</strong>: Research rental market (comparis.ch, homegate.ch)</li><li>[ ] <strong>Language</strong>: Basic German, French, or Italian very helpful</li></ul><h3 id="after-arrival" tabindex="-1">After Arrival <a class="header-anchor" href="#after-arrival" aria-label="Permalink to &quot;After Arrival&quot;">​</a></h3><ul><li>[ ] Register with the cantonal <strong>Einwohnerkontrolle</strong> (residents&#39; registration office)</li><li>[ ] Apply for residence permit (B permit for EU/EFTA citizens)</li><li>[ ] Get health insurance within 3 months</li><li>[ ] Open a Swiss bank account (PostFinance, UBS, Credit Suisse)</li><li>[ ] Register with a GP</li><li>[ ] Get a Swiss phone number (Swisscom, Sunrise, Salt)</li><li>[ ] Connect with TGNS or local LGBTQ+ groups</li></ul><h2 id="practical-information" tabindex="-1">Practical Information <a class="header-anchor" href="#practical-information" aria-label="Permalink to &quot;Practical Information&quot;">​</a></h2><h3 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Category</th><th>Cost (CHF)</th></tr></thead><tbody><tr><td>Rent (1-bedroom, Zurich/Geneva)</td><td>1,500-2,500 CHF/month</td></tr><tr><td>Rent (1-bedroom, smaller cities)</td><td>1,000-1,500 CHF/month</td></tr><tr><td>Groceries</td><td>400-600 CHF/month</td></tr><tr><td>Health insurance</td><td>200-500 CHF/month (basic)</td></tr><tr><td>Public transport pass</td><td>80-150 CHF/month</td></tr><tr><td>Mobile phone plan</td><td>30-60 CHF/month</td></tr></tbody></table><h3 id="languages" tabindex="-1">Languages <a class="header-anchor" href="#languages" aria-label="Permalink to &quot;Languages&quot;">​</a></h3><ul><li><strong>Official languages</strong>: German (63%), French (23%), Italian (8%), Romansh (1%)</li><li><strong>English</strong>: Widely spoken in business and major cities, especially Zurich and Geneva</li><li><strong>Integration</strong>: Learning the local language is important for long-term settlement</li><li>Cantonal language determines which language to learn</li></ul><h3 id="climate" tabindex="-1">Climate <a class="header-anchor" href="#climate" aria-label="Permalink to &quot;Climate&quot;">​</a></h3><ul><li><strong>Alpine climate</strong>: Cold winters, mild summers</li><li><strong>Winter</strong>: -5°C to 5°C (December-February)</li><li><strong>Summer</strong>: 15°C to 25°C (June-August)</li><li><strong>Best time to arrive</strong>: Spring or early autumn</li></ul><h3 id="trans-specific-considerations" tabindex="-1">Trans-Specific Considerations <a class="header-anchor" href="#trans-specific-considerations" aria-label="Permalink to &quot;Trans-Specific Considerations&quot;">​</a></h3><ul><li><strong>Switzerland is generally very safe</strong> for trans people</li><li>Zurich, Geneva, Basel, and Bern have the most accepting environments</li><li>Rural and conservative cantons may be less welcoming</li><li>Healthcare access is best in major cities</li><li>TGNS provides community support and resources</li><li>LGBTQ+ events and spaces are well-established in larger cities</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.sem.admin.ch/" target="_blank" rel="noreferrer">SEM - State Secretariat for Migration</a></li><li><a href="https://www.ch.ch/" target="_blank" rel="noreferrer">CH.ch - Official Swiss Portal</a></li><li><a href="https://www.comparis.ch/" target="_blank" rel="noreferrer">Comparis - Health Insurance Comparison</a></li><li><a href="https://www.homegate.ch/" target="_blank" rel="noreferrer">Homegate - Housing</a></li><li><a href="https://www.tgns.ch/" target="_blank" rel="noreferrer">TGNS - Transgender Network Switzerland</a></li><li><a href="https://www.pinkcross.ch/" target="_blank" rel="noreferrer">Pink Cross</a></li></ul>',31))])}const v=n(h,[["render",c]]);export{b as __pageData,v as default};
